mapper.select:
SELECT ei.elder_id, ei.elder_name, ei.gender, ei.age, ei.id_card, ei.phone, CONCAT(bi.room_number, '-', bi.bed_number) as bed_info, ei.status as check_in_status, ei.care_level, COALESCE( (SELECT SUM(oi.total_amount) FROM order_item oi INNER JOIN order_info o ON oi.order_id = o.order_id WHERE o.elder_id = ei.elder_id AND oi.item_type = 'service_fee' AND o.order_status = '1'), 0 ) as service_balance, COALESCE( (SELECT SUM(oi.total_amount) FROM order_item oi INNER JOIN order_info o ON oi.order_id = o.order_id WHERE o.elder_id = ei.elder_id AND oi.item_type = 'deposit' AND o.order_status = '1'), 0 ) as deposit_balance, COALESCE( (SELECT SUM(oi.total_amount) FROM order_item oi INNER JOIN order_info o ON oi.order_id = o.order_id WHERE o.elder_id = ei.elder_id AND oi.item_type = 'member_fee' AND o.order_status = '1'), 0 ) as member_balance, ba.check_in_date, ba.due_date, ei.emergency_contact, ei.address, ba.monthly_fee, CASE WHEN EXISTS ( SELECT 1 FROM order_info o WHERE o.elder_id = ei.elder_id AND o.order_status = '0' ) THEN 1 ELSE 0 END as has_unpaid_order, bi.institution_id, pi.institution_name, ai.account_id FROM elder_info ei LEFT JOIN bed_allocation ba ON ei.elder_id = ba.elder_id AND (ba.allocation_status = '1' OR ba.allocation_status = '0') LEFT JOIN bed_info bi ON ba.bed_id = bi.bed_id LEFT JOIN pension_institution pi ON bi.institution_id = pi.institution_id LEFT JOIN account_info ai ON ei.elder_id = ai.elder_id WHERE 1=1
AND bi.institution_id IN ( SELECT institution_id FROM sys_user_institution WHERE user_id = #{currentUserId} )
AND ei.elder_name LIKE CONCAT('%', #{elderName}, '%')
AND ei.gender = #{gender}
AND (bi.room_number LIKE CONCAT('%', #{bedInfo}, '%') OR bi.bed_number LIKE CONCAT('%', #{bedInfo}, '%'))
AND ei.status = #{checkInStatus}
AND bi.institution_id = #{institutionId}
ORDER BY ei.create_time DESC
